package com.seaquake6324.civitas.infrastructure.world;
import com.seaquake6324.civitas.application.RegisterPatrolRouteService;import com.seaquake6324.civitas.domain.City;import com.seaquake6324.civitas.domain.building.*;import com.seaquake6324.civitas.infrastructure.config.CivitasConfig;import com.seaquake6324.civitas.infrastructure.network.PatrolRouteModePayload;import com.seaquake6324.civitas.infrastructure.persistence.*;import java.util.*;import net.minecraft.core.*;import net.minecraft.network.chat.Component;import net.minecraft.server.level.*;import net.minecraft.world.level.ChunkPos;import net.neoforged.neoforge.network.PacketDistributor;
/** Server-authoritative bounded RTS-style patrol route drawing. Routes do not grant coverage by themselves. */
public final class PatrolRouteManager{
 private static final Map<UUID,Session>ACTIVE=new HashMap<>();private static final RegisterPatrolRouteService SERVICE=new RegisterPatrolRouteService();private static long sessions,nodesAccepted,rejected,confirmed,expired,totalSamples,postLookupTruncations,totalMicros,maxMicros;private static String lastReason="not_run";
 public static void begin(ServerPlayer player,City city){if(city==null||!city.mayCommandMilitary(player.getUUID())){notice(player,"civitas.patrol.failure.not_commander");return;}if(ThreatSavedData.get(player.level().getServer()).readOnly()){notice(player,"civitas.patrol.failure.read_only");return;}BuildingRegistrationManager.remove(player);StorageAuthorizationManager.remove(player);TerritoryExpansionManager.remove(player);CoreMoveManager.remove(player);long now=player.level().getGameTime();ACTIVE.put(player.getUUID(),new Session(city.id(),city.revision(),now+CivitasConfig.PATROL_ROUTE_SESSION_TICKS.get(),null,new ArrayList<>()));sessions++;sync(player,ACTIVE.get(player.getUUID()));notice(player,"civitas.patrol.select_post_node");}
 public static boolean active(ServerPlayer player){return ACTIVE.containsKey(player.getUUID());}public static void remove(ServerPlayer player){if(ACTIVE.remove(player.getUUID())!=null)PacketDistributor.sendToPlayer(player,PatrolRouteModePayload.stopped());}
 public static void select(ServerLevel level,ServerPlayer player,BlockPos clicked,Direction face){Session s=ACTIVE.get(player.getUUID());if(s==null)return;long now=level.getGameTime();if(now>s.expiresAt){expired++;lastReason="session_expired";remove(player);notice(player,"civitas.patrol.failure.expired");return;}City city=CitySavedData.get(level.getServer()).byId(s.cityId).orElse(null);if(city==null||city.revision()!=s.cityRevision||!city.mayCommandMilitary(player.getUUID())||!city.dimension().equals(level.dimension().identifier().toString())){rejected++;lastReason="stale_city";remove(player);notice(player,"civitas.patrol.failure.stale_city");return;}if(player.isShiftKeyDown()&&level.getBlockEntity(clicked) instanceof CityCoreBlockEntity core&&city.id().equals(core.cityId())){remove(player);lastReason="cancelled";notice(player,"civitas.patrol.cancelled");return;}if(player.isShiftKeyDown()){confirm(level,player,city,s,now);return;}BlockPos node=clicked.relative(face).immutable();if(!city.ownsChunk(city.dimension(),ChunkPos.pack(node))){reject(player,"outside_territory");return;}if(!standable(level,node)){reject(player,"not_standable");return;}BuildingRecord post=s.postId==null?postAt(level,city,node):BuildingSavedData.get(level.getServer()).byId(s.postId).orElse(null);if(s.postId==null&&post==null){reject(player,"not_at_post");return;}if(post==null||post.status()!=BuildingStatus.VALID||post.purpose()!=BuildingPurpose.GUARD_POST){reject(player,"stale_post");return;}if(s.nodes.size()>=CivitasConfig.PATROL_ROUTE_NODE_CAP.get()){reject(player,"node_cap");return;}if(!s.nodes.isEmpty()&&distance(s.nodes.getLast(),node)>CivitasConfig.PATROL_ROUTE_SEGMENT_BLOCKS.get()){reject(player,"segment_too_long");return;}if(!s.nodes.isEmpty()&&s.nodes.getLast().equals(node)){reject(player,"duplicate_node");return;}s.nodes.add(node);Session next=new Session(s.cityId,s.cityRevision,s.expiresAt,post.id(),s.nodes);ACTIVE.put(player.getUUID(),next);nodesAccepted++;lastReason="node_added";sync(player,next);level.sendParticles(net.minecraft.core.particles.ParticleTypes.HAPPY_VILLAGER,node.getX()+.5,node.getY()+.2,node.getZ()+.5,4,.12,.08,.12,0);notice(player,s.nodes.size()==1?"civitas.patrol.add_nodes":"civitas.patrol.node_added");}
 private static void confirm(ServerLevel level,ServerPlayer player,City city,Session s,long now){if(s.nodes.size()<2){reject(player,"too_few_nodes");return;}BuildingRecord post=s.postId==null?null:BuildingSavedData.get(level.getServer()).byId(s.postId).orElse(null);long began=System.nanoTime();Evidence evidence=validate(level,city,post,s.nodes);long micros=Math.max(0,(System.nanoTime()-began)/1_000);totalMicros+=micros;maxMicros=Math.max(maxMicros,micros);totalSamples+=evidence.samples;var result=SERVICE.register(ThreatSavedData.get(level.getServer()),new RegisterPatrolRouteService.Request(UUID.randomUUID(),city,player.getUUID(),post,s.cityRevision,post==null?0:post.revision(),s.nodes.stream().map(BlockPos::asLong).toList(),now,CivitasConfig.PATROL_ROUTE_CITY_CAP.get(),new RegisterPatrolRouteService.Evidence(s.nodes.size(),evidence.samples,evidence.inside,evidence.atPost,evidence.standable,evidence.segments,!evidence.complete,micros)));if(result.success()){confirmed++;lastReason="route_registered";remove(player);notice(player,"civitas.patrol.registered");}else{rejected++;lastReason="register_"+result.failure().name().toLowerCase(Locale.ROOT);notice(player,"civitas.patrol.failure."+result.failure().name().toLowerCase(Locale.ROOT));}}
 private static Evidence validate(ServerLevel level,City city,BuildingRecord post,List<BlockPos>nodes){boolean inside=true,atPost=post!=null&&post.cells().contains(nodes.getFirst().asLong()),allStandable=true,segments=true,complete=true;int samples=0,cap=CivitasConfig.PATROL_ROUTE_PATH_SAMPLE_CAP.get();for(BlockPos node:nodes){inside&=city.ownsChunk(city.dimension(),ChunkPos.pack(node));allStandable&=standable(level,node);}for(int i=1;i<nodes.size();i++){BlockPos a=nodes.get(i-1),b=nodes.get(i);double distance=distance(a,b);if(distance>CivitasConfig.PATROL_ROUTE_SEGMENT_BLOCKS.get()){segments=false;continue;}int steps=Math.max(1,(int)Math.ceil(distance));for(int step=1;step<steps;step++){if(samples++>=cap){complete=false;break;}double t=(double)step/steps;BlockPos p=new BlockPos((int)Math.round(a.getX()+(b.getX()-a.getX())*t),(int)Math.round(a.getY()+(b.getY()-a.getY())*t),(int)Math.round(a.getZ()+(b.getZ()-a.getZ())*t));if(!level.hasChunkAt(p)||!standable(level,p)){allStandable=false;break;}}if(!complete)break;}return new Evidence(samples,inside,atPost,allStandable,segments,complete);}
 private static BuildingRecord postAt(ServerLevel level,City city,BlockPos node){var page=BuildingSavedData.get(level.getServer()).recordsInChunk(city.id(),city.dimension(),ChunkPos.pack(node),CivitasConfig.SECURITY_BUILDING_RECORD_LIMIT_PER_CELL.get());if(page.truncated()){postLookupTruncations++;lastReason="post_lookup_truncated";return null;}return page.records().stream().filter(b->b.purpose()==BuildingPurpose.GUARD_POST&&b.status()==BuildingStatus.VALID&&b.cells().contains(node.asLong())).min(Comparator.comparing(BuildingRecord::id)).orElse(null);}private static boolean standable(ServerLevel level,BlockPos p){return level.hasChunkAt(p)&&level.isInWorldBounds(p)&&level.getBlockState(p).getCollisionShape(level,p).isEmpty()&&level.getBlockState(p.above()).getCollisionShape(level,p.above()).isEmpty()&&level.getBlockState(p.below()).blocksMotion()&&level.getFluidState(p).isEmpty();}private static double distance(BlockPos a,BlockPos b){return Math.sqrt(a.distSqr(b));}
 private static void reject(ServerPlayer player,String reason){rejected++;lastReason=reason;notice(player,"civitas.patrol.failure."+reason);}private static void sync(ServerPlayer player,Session s){PacketDistributor.sendToPlayer(player,new PatrolRouteModePayload(true,List.copyOf(s.nodes),CivitasConfig.PATROL_ROUTE_NODE_CAP.get(),CivitasConfig.PATROL_ROUTE_SEGMENT_BLOCKS.get()));}private static void notice(ServerPlayer p,String key){p.sendSystemMessage(Component.translatable(key),true);}public static Metrics metrics(){return new Metrics(sessions,nodesAccepted,rejected,confirmed,expired,totalSamples,postLookupTruncations,totalMicros/Math.max(1,confirmed+rejected),maxMicros,ACTIVE.size(),lastReason);}public record Metrics(long sessions,long nodesAccepted,long rejected,long confirmed,long expired,long pathSamples,long postLookupTruncations,long averageMicros,long maxMicros,int activeSessions,String lastReason){}private record Session(UUID cityId,long cityRevision,long expiresAt,UUID postId,ArrayList<BlockPos>nodes){}private record Evidence(int samples,boolean inside,boolean atPost,boolean standable,boolean segments,boolean complete){}private PatrolRouteManager(){}
}
